const stages=['commit','execute','observe','validate','reward','risk','memory','policy'];
const presets={
  software:'Produce a replayable evidence package for a bounded software-quality review, including assumptions, validator notes, cost/risk ledger, and human-review handoff.',
  research:'Create a public-safe evidence map for a market-intelligence question with source boundaries, contradictions, replay notes, and decision options.',
  policy:'Evaluate a proposed tool-use workflow under policy constraints, risk gates, rollback readiness, and public/private evidence separation.',
  science:'Package a scientific workflow rehearsal with hypothesis, simulated test plan, validator notes, uncertainty ledger, and replay requirements.',
  settlement:'Rehearse an AGIJobManager proof-settlement lifecycle: job, proof, validation, settlement readiness, Chronicle entry, and human review.'
};
const state={events:[],last:null,accepted:0,quarantined:0,policy:0};
const $=id=>document.getElementById(id);
const vals=()=>({
  replayability:+$('replayability').value,
  validator:+$('validator').value,
  delayed:+$('delayed').value,
  reward:+$('reward').value,
  costrisk:+$('costrisk').value,
  boundary:+$('boundary').value
});
function syncLabels(){document.querySelectorAll('.xp-sliders label').forEach(l=>{const input=l.querySelector('input'); const out=l.querySelector('span'); if(out) out.textContent=input.value;});}
function integrity(v){return Math.round((v.replayability*1.2+v.validator*1.1+v.delayed*.9+v.reward+v.costrisk+v.boundary*1.2)/6.4);}
function rewardHack(v){return Math.max(0,Math.round((100-v.reward)*.42+(100-v.validator)*.25+(100-v.delayed)*.2+(100-v.costrisk)*.13));}
function verdict(v){const I=integrity(v), H=rewardHack(v); if(v.boundary<55) return 'QUARANTINE_PRIVATE_APPENDIX'; if(v.replayability<58 || v.validator<55) return 'EVIDENCE_ONLY_NO_POLICY_UPDATE'; if(H>43) return 'QUARANTINE_REWARD_SIGNAL'; if(v.delayed<45) return 'DELAYED_OUTCOME_REQUIRED'; if(I>=76) return 'POLICY_UPDATE_ALLOWED_AFTER_HUMAN_REVIEW'; return 'EXPERIENCE_ADMITTED_TO_CHRONICLE';}
function event(kind,text,cls='') {const e={time:new Date().toISOString(),kind,text}; state.events.push(e); const div=document.createElement('div'); div.className='xp-event '+cls; div.textContent=`${kind.toUpperCase()} · ${text}`; $('experienceStream').prepend(div);}
function renderStage(active=-1){$('stagebar').innerHTML=stages.map((s,i)=>`<div class="${i<=active?'active':''}">${s}</div>`).join('');}
function buildObject(mode='normal'){const v=vals(); const I=integrity(v); const H=rewardHack(v); const out=verdict(v); const obj={
  object:'SovereignExperienceDocket',version:'v24',demo:'Sovereign Experience Stream',generatedAt:new Date().toISOString(),publicSafety:{noUserDataWanted:true,noAccount:true,noCookies:true,noAnalytics:true,noStorage:true,noWalletConnection:true,noNetworkRequest:true,noTransactionBroadcast:true,noProductionAuthority:true},
  goalOSCommit:{objective:$('objective').value.slice(0,700),riskClass:'public-safe-demo',claimBoundary:'browser-local demonstration only; no factual certification; no external action'},
  sovereignExperienceEvent:{state:'proof-cleared-review',action:'bounded mission run',observation:'evidence package generated locally',groundedReward:{validatorSignal:v.validator,delayedOutcomeSignal:v.delayed,rewardIntegrity:v.reward,rewardHackingPressure:H},validatorDecision:v.validator>=55?'ACCEPT_FOR_REVIEW':'REJECT_OR_REVISE',costRiskLedger:{costRiskAccounting:v.costrisk,criticalSafetyIncidents:0,externalActions:0},privacyBoundary:{publicPrivateBoundary:v.boundary,privateDataWanted:false},memoryUpdate:out.includes('POLICY_UPDATE_ALLOWED')||out.includes('CHRONICLE')?'ChronicleEntryCandidate':'No memory authority'},
  checks:{replayability:v.replayability,validatorIndependence:v.validator,delayedOutcome:v.delayed,rewardIntegrity:v.reward,costRiskAccounting:v.costrisk,publicPrivateBoundary:v.boundary,experienceIntegrity:I,rewardHackingPressure:H},
  result:{verdict:out,canUpdateProductionPolicy:out==='POLICY_UPDATE_ALLOWED_AFTER_HUMAN_REVIEW',requiresHumanReview:true,mode},
  protocolObjects:['GoalOSCommit','RunCommitment','ProofPacket','EvalAttestation','SelectionCertificate','ExperienceEvent','GroundedRewardLedger','ChronicleEntry','PolicyUpdateReceipt']
}; return obj;}
function renderResult(obj){state.last=obj; $('integrityScore').textContent=obj.checks.experienceIntegrity; $('rewardHack').textContent=obj.checks.rewardHackingPressure; $('policyStatus').textContent=obj.result.verdict; $('experienceJson').textContent=JSON.stringify(obj,null,2); $('validatorLane').innerHTML=`<b>${obj.sovereignExperienceEvent.validatorDecision}</b><br>Validator independence: ${obj.checks.validatorIndependence}/100<br>Immediate acceptance is not production authority.`; $('rewardLane').innerHTML=`<b>${obj.result.canUpdateProductionPolicy?'GOVERNED UPDATE CANDIDATE':'WITHHOLD / QUARANTINE'}</b><br>Delayed outcome: ${obj.checks.delayedOutcome}/100<br>Reward-hacking pressure: ${obj.checks.rewardHackingPressure}/100`; $('xpAccepted').textContent=state.accepted; $('xpQuarantine').textContent=state.quarantined; $('xpPolicy').textContent=state.policy;}
async function run(mode='normal'){state.events=[]; $('experienceStream').innerHTML=''; renderStage(-1); const v=vals(); const rows=[['commit','GoalOSCommit sealed with public-safe objective and claim boundary.'],['execute','RunCommitment resolves agent roles, tool permissions, context roots, and budget.'],['observe','ProofPacket captures trace root, output hash, validator notes, cost, latency, and evidence pointer.'],['validate',v.validator>=55?'Evaluator quorum accepts the event for review.':'Validator independence too weak; revise before admission.'],['reward',rewardHack(v)<=43?'Grounded reward ledger remains below reward-hacking threshold.':'Reward signal is suspicious; quarantine before learning.'],['risk',v.boundary>=55?'Public/private proof boundary passes data-zero scan.':'Public/private boundary is weak; private appendix quarantine required.'],['memory',integrity(v)>=62?'Chronicle candidate created with replay and rollback metadata.':'No Chronicle authority; preserve as warning only.'],['policy','Policy update remains human-review gated.']];
 for(let i=0;i<rows.length;i++){renderStage(i); await new Promise(r=>setTimeout(r,90)); const cls=rows[i][1].includes('weak')||rows[i][1].includes('suspicious')||rows[i][1].includes('quarantine')?'warn':''; event(rows[i][0],rows[i][1],cls);}
 const obj=buildObject(mode); if(obj.result.verdict.includes('POLICY_UPDATE_ALLOWED')){state.accepted++; state.policy++;} else if(obj.result.verdict.includes('QUARANTINE')||obj.result.verdict.includes('REQUIRED')){state.quarantined++;} else {state.accepted++;} renderResult(obj);}
function stress(){const ids=['replayability','validator','delayed','reward','costrisk','boundary']; ids.forEach((id,i)=>{$(id).value=[43,48,38,41,55,79][i];}); syncLabels(); run('stress-test');}
function reset(){Object.entries({replayability:84,validator:78,delayed:63,reward:72,costrisk:76,boundary:91}).forEach(([k,v])=>$(k).value=v); $('missionPreset').value='software'; $('objective').value=presets.software; state.events=[];state.last=null;state.accepted=0;state.quarantined=0;state.policy=0; $('experienceStream').innerHTML=''; $('experienceJson').textContent='Run the stream to generate a SovereignExperienceEvent.'; $('validatorLane').textContent='Awaiting run.'; $('rewardLane').textContent='Awaiting run.'; $('integrityScore').textContent='—'; $('rewardHack').textContent='—'; $('policyStatus').textContent='NOT RUN'; $('xpAccepted').textContent='0'; $('xpQuarantine').textContent='0'; $('xpPolicy').textContent='0'; renderStage(-1); syncLabels();}
function download(){const obj=state.last||buildObject('manual-export'); const blob=new Blob([JSON.stringify(obj,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-sovereign-experience-docket-v24.json'; document.body.append(a); a.click(); a.remove(); setTimeout(()=>URL.revokeObjectURL(a.href),800);}
async function copyBrief(){const obj=state.last||buildObject('brief'); const text=`Sovereign Experience Stream: ${obj.result.verdict}. Experience integrity ${obj.checks.experienceIntegrity}/100. Reward-hacking pressure ${obj.checks.rewardHackingPressure}/100. Public-safe local demo only; human review required before policy authority.`; try{await navigator.clipboard.writeText(text); event('brief','Review brief copied locally.');}catch{event('brief',text);}}
function field(){const c=$('experienceField'),ctx=c.getContext('2d'); let dots=[]; function resize(){c.width=innerWidth*devicePixelRatio;c.height=innerHeight*devicePixelRatio;dots=Array.from({length:130},()=>({x:Math.random()*c.width,y:Math.random()*c.height,v:(.22+Math.random()*.75)*devicePixelRatio,r:(.7+Math.random()*2.3)*devicePixelRatio,a:.25+Math.random()*.65}));} function draw(){ctx.clearRect(0,0,c.width,c.height); for(const d of dots){ctx.beginPath();ctx.fillStyle=`rgba(99,255,218,${d.a})`;ctx.arc(d.x,d.y,d.r,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.strokeStyle=`rgba(104,216,255,${d.a*.24})`;ctx.moveTo(d.x,d.y+d.r*8);ctx.lineTo(d.x,d.y+d.r*22);ctx.stroke();d.y-=d.v;if(d.y<-20){d.y=c.height+20;d.x=Math.random()*c.width;}} requestAnimationFrame(draw);} addEventListener('resize',resize,{passive:true}); resize(); draw();}
$('missionPreset').addEventListener('change',e=>{$('objective').value=presets[e.target.value];}); document.querySelectorAll('.xp-sliders input').forEach(i=>i.addEventListener('input',syncLabels)); $('runExperience').addEventListener('click',()=>run('normal')); $('stressExperience').addEventListener('click',stress); $('resetExperience').addEventListener('click',reset); $('downloadDocket').addEventListener('click',download); $('copyBrief').addEventListener('click',copyBrief); renderStage(-1); syncLabels(); field();
